return items.map(item => {

  const data = item.json;

  return {
    json: {
      campaignId: "CMP-" + data.ID.toString().padStart(5, "0"),
      campaignName: data.Campaign,

      profile:
        data.Platform === "TikTok"
          ? "story"
          : "portrait",

      platform:
        data.Platform.toLowerCase(),

      theme: "spread-light",

      headline: data.Headline,

      subHeadline: data["Sub Headline"],

      caption: data.Caption,

      cta: data.CTA,

      backgroundImage: data["Image URL"],

      overlayText: data["Overlay Text"],

      imageStyle: data["Image Style"],

      designStyle: data["Design Style"],

      hashtags: data.Hashtags,

      product: data.Product,

      audience: data.Audience,

      goal: data.Goal,

      date: data.Date
    }
  };

});

